        category: opp.category || '',
        source: 'Grants.gov',
        awardFloor: awardFloor,
        awardCeiling: awardCeiling,
        status: opp.oppStatus || opp.status || '',
        metadata: {
          eligibility: eligibility || null,
          additionalEligibility: additionalEligibility || null,
          estimatedFunding: estimatedFunding || null,
          costSharing: costSharing || null,
          numberOfAwards: numberOfAwards || null,
          categoryOfFunding: categoryOfFunding || null,
          fundingInstruments: fundingInstruments || null,
          responseDateDesc: responseDateDesc || null,
          archiveDate: archiveDate || null,
          fundingDescLink: fundingDescLink || null,
          contactInfo: contactInfo || null,
          cfdaNumbers: cfdaNumbers.length > 0 ? cfdaNumbers : null,
        }
      }
    });
  }
}

return grants.length > 0 ? grants : [{ json: { empty: true, source: 'grants.gov' } }];

// Parse Grand Challenges list page via embedded __NEXT_DATA__ JSON blob.
// Emits only currently-open challenges (date_end in the future).
const html = $input.first().json.data || $input.first().json.body || '';
if (typeof html !== 'string' || html.length < 500) {
  return [{ json: { empty: true, source: 'Gates Grand Challenges' } }];
}

const m = html.match(/<script id="__NEXT_DATA__"[^>]*>([\s\S]*?)<\/script>/);
if (!m) {
  return [{ json: { empty: true, source: 'Gates Grand Challenges', reason: 'no __NEXT_DATA__' } }];
}

let data;
try {
  data = JSON.parse(m[1]);
} catch (e) {
  return [{ json: { empty: true, source: 'Gates Grand Challenges', reason: 'parse failed' } }];
}

const list = data?.props?.pageProps?.initialData?.listing?.data;
if (!Array.isArray(list) || list.length === 0) {
  return [{ json: { empty: true, source: 'Gates Grand Challenges' } }];
}

const origin = 'https://gcgh.grandchallenges.org';
const nowSec = Math.floor(Date.now() / 1000);
const stripHtml = (s) => (s || '').replace(/<[^>]+>/g, '').replace(/&nbsp;/g, ' ').replace(/\s+/g, ' ').trim();
const toDateStr = (unixSec) => {
  if (!unixSec) return null;
  const d = new Date(unixSec * 1000);
  if (isNaN(d.getTime())) return null;
  return d.toISOString().split('T')[0];
};

const grants = [];
for (const c of list) {
  if (c.published === false || c.hidden === true) continue;

  const endSec = parseInt(c.date_end, 10);
  if (!endSec || endSec <= nowSec) continue; // closed or no deadline

  const title = (c.main_title || c.title || '').trim();
  if (!title) continue;

  const rel = c.url || '';
  const link = rel.startsWith('http') ? rel : origin + rel;
  const slug = (rel || title).replace(/^https?:\/\//, '').replace(/[^a-z0-9]+/gi, '-').slice(0, 80);

  const openDate = toDateStr(parseInt(c.date, 10)) || new Date().toISOString().split('T')[0];
  const closeDate = toDateStr(endSec);

  grants.push({ json: {
    id: 'GCGH-' + (c.id || c.challenge_uuid || slug),
    oppNum: 'GCGH-' + (c.id || c.challenge_uuid || slug),
    title: title,
    description: stripHtml(c.opportunity_description_summary) || stripHtml(c.opportunity_description).slice(0, 1000) || 'Gates Foundation Grand Challenges open call.',
    link: c.apply_link || link,
    openDate: openDate,
    closeDate: closeDate,
    agency: 'Bill & Melinda Gates Foundation',
    agencyCode: 'GATES-GCGH',
    category: 'Philanthropic - Foundation',
    source: 'Gates Grand Challenges',
    awardFloor: 0,
    awardCeiling: 0,
    status: 'posted',
    metadata: {
      sourceLevel: 'philanthropic',
      funder: 'Gates Foundation',
      program: 'Grand Challenges',
      initiative: c.initiative_title || null,
      challenge_goal: c.challenge_goal || null,
      challenge_url: link,
    }
  }});
}

return grants.length > 0 ? grants : [{ json: { empty: true, source: 'Gates Grand Challenges' } }];
